// NOTES
// ============================================================

// ============================================================
// SEARCH
// ============================================================
function setupSearch() {
  const input = document.getElementById('globalSearch');
  const results = document.getElementById('searchResults');
  if (!input || !results) return;

  input.addEventListener('input', () => {
    const q = input.value.toLowerCase().trim();
    if (q.length < 2) { results.hidden = true; return; }

    const matches = [];

    // Search content titles
    for (const [id, html] of Object.entries(CONTENT)) {
      const text = html.replace(/<[^>]*>/g, '').toLowerCase();
      if (text.includes(q)) {
        const unitNum = id.split('.')[0];
        matches.push({ title: id + ' ' + (html.match(/<h3>(.*?)<\/h3>/)?.[1]?.replace(/<[^>]*>/g, '') || id), section: 'unit' + unitNum, type: 'Topic' });
      }
    }

    // Search flashcards
    FLASHCARDS.forEach(c => {
      if (c.term.toLowerCase().includes(q) || c.def.toLowerCase().includes(q)) {
        matches.push({ title: c.term, section: 'flashcards', type: 'Flashcard' });
      }
    });

    const list = results.querySelector('.search-results-list');
    if (list) {
      list.innerHTML = matches.slice(0, 8).map(m => `
        <li class="search-result-item" data-section="${m.section}">
          <span class="search-result-type">${m.type}</span>
          <span class="search-result-title">${m.title}</span>
        </li>
      `).join('') || '<li class="search-no-results">No results found</li>';
    }
    results.hidden = false;
  });

  results.addEventListener('click', (e) => {
    const item = e.target.closest('.search-result-item');
    if (item) {
      navigate(item.dataset.section);
      results.hidden = true;
      input.value = '';
    }
  });

  document.addEventListener('click', (e) => {
    if (!e.target.closest('#searchWrapper')) results.hidden = true;
  });

  // Ctrl+K shortcut
  document.addEventListener('keydown', (e) => {
    if ((e.ctrlKey || e.metaKey) && e.key === 'k') { e.preventDefault(); input.focus(); }
    if (e.key === 'Escape') results.hidden = true;
  });
}

// ============================================================
// DARK MODE
// ============================================================
function setupDarkMode() {
  const btn = document.getElementById('darkModeToggle');
  if (!btn) return;
  if (state.darkMode) document.documentElement.setAttribute('data-theme', 'dark');

  btn.addEventListener('click', () => {
    state.darkMode = !state.darkMode;
    document.documentElement.setAttribute('data-theme', state.darkMode ? 'dark' : 'light');
    btn.querySelector('i').className = state.darkMode ? 'fas fa-sun' : 'fas fa-moon';
    saveState();
  });
  if (state.darkMode) btn.querySelector('i').className = 'fas fa-sun';
}

// ============================================================
// MODALS
// ============================================================
function setupModals() {
  document.querySelectorAll('[data-close-modal]').forEach(btn => {
    btn.addEventListener('click', () => {
      const modal = document.getElementById(btn.dataset.closeModal);
      if (modal) modal.hidden = true;
    });
  });

  // Close on overlay click
  document.querySelectorAll('.modal-overlay').forEach(overlay => {
    overlay.addEventListener('click', (e) => {
      if (e.target === overlay) overlay.hidden = true;
    });
  });
}

// ============================================================
// SIDEBAR
// ============================================================
function openSidebar() {
  const sidebar = document.getElementById('sidebar');
  const overlay = document.getElementById('sidebarOverlay');
  if (sidebar) sidebar.classList.add('open');
  if (overlay) overlay.classList.add('visible');
}

function closeSidebar() {
  const sidebar = document.getElementById('sidebar');
  const overlay = document.getElementById('sidebarOverlay');
  if (sidebar) sidebar.classList.remove('open');
  if (overlay) overlay.classList.remove('visible');
}

function setupSidebar() {
  const toggle = document.getElementById('sidebarToggle');
  const sidebar = document.getElementById('sidebar');
  const trigger = document.getElementById('sidebarTrigger');
  const overlay = document.getElementById('sidebarOverlay');
  if (!sidebar) return;

  // Toggle button in header
  if (toggle) toggle.addEventListener('click', () => {
    sidebar.classList.contains('open') ? closeSidebar() : openSidebar();
  });

  // Hover trigger on left edge — open sidebar
  if (trigger) {
    trigger.addEventListener('mouseenter', () => openSidebar());
  }

  // Keep sidebar open while mouse is over it
  sidebar.addEventListener('mouseleave', (e) => {
    // Only auto-close if mouse leaves to the right (not into trigger zone)
    if (e.clientX > 5) {
      closeSidebar();
    }
  });

  // Click overlay to close
  if (overlay) overlay.addEventListener('click', closeSidebar);

  // Close on Escape
  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape' && sidebar.classList.contains('open')) {
      closeSidebar();
    }
  });

  // Nav item clicks — navigate and close sidebar
  document.querySelectorAll('.nav-item[data-section]').forEach(item => {
    item.querySelector('.nav-link')?.addEventListener('click', (e) => {
      e.preventDefault();
      const section = item.dataset.section;

      // Toggle sub-nav for items with children
      if (item.classList.contains('has-children')) {
        item.classList.toggle('expanded');
        // Don't close sidebar when expanding sub-nav, only navigate
        navigate(section);
        return;
      }

      navigate(section);
      closeSidebar();
    });
  });

  // Sub-topic clicks
  document.querySelectorAll('.nav-sublist li').forEach(item => {
    item.addEventListener('click', (e) => {
      e.stopPropagation();
      const subtopic = item.dataset.subtopic;
      const parentSection = item.closest('.nav-item')?.dataset.section;
      if (parentSection && subtopic) {
        navigate(parentSection);
        // Click the corresponding tab
        setTimeout(() => {
          const tab = document.querySelector(`#section-${parentSection} .topic-tab[data-tab="${subtopic}"]`);
          if (tab) tab.click();
        }, 50);
        closeSidebar();
      }
    });
  });

  // Quick access links
  document.querySelectorAll('.quick-access-card[data-section]').forEach(a => {
    a.addEventListener('click', (e) => {
      e.preventDefault();
      navigate(a.dataset.section);
      closeSidebar();
    });
  });

  // Homepage glass button links
  document.querySelectorAll('.glass-btn[data-section]').forEach(btn => {
    btn.addEventListener('click', (e) => {
      e.preventDefault();
      navigate(btn.dataset.section);
    });
  });
}

// ============================================================
// TOAST
// ============================================================
function showToast(msg) {
  const container = document.getElementById('toastContainer');
  if (!container) return;
  const toast = document.createElement('div');
  toast.className = 'toast toast-success';
  toast.textContent = msg;
  container.appendChild(toast);
  requestAnimationFrame(() => toast.classList.add('visible'));
  setTimeout(() => {
    toast.classList.remove('visible');
    setTimeout(() => toast.remove(), 300);
  }, 2500);
}

// ============================================================
// BACK TO TOP
// ============================================================
function setupBackToTop() {
  const btn = document.getElementById('backToTop');
  const main = document.getElementById('mainContent');
  if (!btn || !main) return;

  main.addEventListener('scroll', () => {
    btn.hidden = main.scrollTop < 300;
  });

  btn.addEventListener('click', () => main.scrollTo({ top: 0, behavior: 'smooth' }));
}

// ============================================================
// KEYBOARD SHORTCUTS (Flashcards)
// ============================================================
function setupKeyboard() {
  document.addEventListener('keydown', (e) => {
    if (state.currentSection !== 'flashcards') return;
    if (e.target.matches('input, textarea, select')) return;

    if (e.code === 'Space') { e.preventDefault(); state.flashcardFlipped = !state.flashcardFlipped; renderFlashcard(); }
    if (e.code === 'ArrowLeft' && state.flashcardIndex > 0) { state.flashcardIndex--; state.flashcardFlipped = false; renderFlashcard(); }
    if (e.code === 'ArrowRight' && state.flashcardIndex < state.flashcardDeck.length - 1) { state.flashcardIndex++; state.flashcardFlipped = false; renderFlashcard(); }
  });
}

// ============================================================
// RESET PROGRESS
// ============================================================
function setupReset() {
  document.getElementById('resetProgressBtn')?.addEventListener('click', () => {
    if (!confirm('Reset all progress? This cannot be undone.')) return;
    state.completedTopics.clear();
    state.masteredCards.clear();
    state.notes = [];
    state.sessions = [];
    saveState();
    updateDashboardStats();
    setupMarkComplete();
    showToast('Progress reset.');
  });
}

