// DAILY TIP
// ============================================================
function setupDailyTip() {
  const tips = [
    "Use STEEPLE to analyze any business case study - it helps organize external factors systematically.",
    "When answering 'evaluate' questions, always present both sides and give a justified conclusion.",
    "Practice drawing break-even charts by hand - you may need to construct one in the exam.",
    "Profitability is not the same as Liquidity. A profitable business can still fail if it runs out of cash.",
    "For 10-mark questions, aim for 3 arguments for and 3 against, plus a balanced conclusion.",
    "Link motivation theories to real examples - examiners reward application over memorisation.",
    "Always define key terms at the start of your answer - easy marks!",
    "In ratio analysis, always interpret the numbers - explain what they mean for the business.",
    "Use the Ansoff Matrix to analyze growth strategies - it's a versatile and commonly examined tool.",
    "For Paper 2, practice reading case studies quickly and identifying the key issues first.",
    "Remember: Herzberg says pay is a hygiene factor, not a motivator. This distinction is exam gold.",
    "When discussing stakeholders, always consider who has the most INFLUENCE and why."
  ];
  const tipEl = document.getElementById('studyTipText');
  const tipBtn = document.getElementById('newTipBtn');

  function showTip() {
    const idx = Math.floor(Math.random() * tips.length);
    if (tipEl) tipEl.textContent = '"' + tips[idx] + '"';
  }

  showTip();
  tipBtn?.addEventListener('click', showTip);
}

// ============================================================
// INIT
// ============================================================
function init() {
  loadState();
  populateAllContent();
  setupTabs();
  setupMarkComplete();
  setupSidebar();
  setupSearch();
  setupDarkMode();
  setupModals();
  setupFlashcardControls();
  setupExamPractice();
  setupBackToTop();
  setupKeyboard();
  setupReset();
  setupDailyTip();
  updateDashboardStats();

  // Set date on dashboard
  const dateEl = document.getElementById('dashboardDate');
  if (dateEl) dateEl.textContent = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

  // Header scroll shadow
  const header = document.getElementById('appHeader');
  document.getElementById('mainContent')?.addEventListener('scroll', () => {
    const scrolled = document.getElementById('mainContent').scrollTop > 8;
    header?.classList.toggle('scrolled', scrolled);
  });

  // Navigate to dashboard (hides all other sections)
  navigate(state.currentSection || 'dashboard');
}

document.addEventListener('DOMContentLoaded', init);
